:root {
  --accent: #6fe3ff;
  --accent-warm: #ffb86b;
  --ink: #e8f4ff;
  --panel-bg: rgba(8, 14, 26, 0.82);
  --pin-shell: #171126;
  --pin-rim: rgba(255, 244, 232, 0.96);
  --pin-core: #d79e3a;
  --pin-shadow: rgba(2, 4, 10, 0.72);
}

* { margin: 0; padding: 0; box-sizing: border-box; }

html, body {
  width: 100%;
  height: 100%;
  overflow: hidden;
  background: #02040a;
  color: var(--ink);
  font-family: "SF Mono", "JetBrains Mono", ui-monospace, Menlo, monospace;
  cursor: default;
}

#scene {
  position: fixed;
  inset: 0;
  display: block;
  width: 100%;
  height: 100%;
}

#ui {
  position: fixed;
  inset: 0;
  pointer-events: none;
  z-index: 10;
}

#hud {
  position: absolute;
  top: 28px;
  left: 32px;
}

.hud-title {
  font-size: 26px;
  letter-spacing: 0.42em;
  font-weight: 600;
  text-shadow: 0 0 18px rgba(111, 227, 255, 0.55);
}

#hint {
  position: absolute;
  bottom: 26px;
  left: 50%;
  transform: translateX(-50%);
  font-size: 12px;
  letter-spacing: 0.12em;
  opacity: 0.55;
  white-space: nowrap;
}

/* ---------- title screen (arcade boot menu) ---------- */

/* The orbit view keeps rendering behind it — only a soft vignette for
   legibility, so the planet stays the attract backdrop. */
#title-screen {
  position: absolute;
  inset: 0;
  z-index: 35;
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  pointer-events: auto;
  background: radial-gradient(ellipse at 50% 44%, rgba(2, 4, 10, 0.55), rgba(2, 4, 10, 0.85));
  transition: opacity 0.6s ease;
}
#title-screen.is-leaving {
  opacity: 0;
  pointer-events: none;
}
#title-screen.hidden { display: none; }
#title-screen.is-leaderboard-open {
  background: rgba(2, 4, 10, 0.9);
}
#title-screen.is-leaderboard-open .ts-logo,
#title-screen.is-leaderboard-open .ts-tag,
#title-screen.is-leaderboard-open .ts-menu,
#title-screen.is-leaderboard-open .ts-panel,
#title-screen.is-leaderboard-open #ts-story {
  visibility: hidden;
  pointer-events: none;
}

/* While the title is up, the in-game chrome stays out of the shot. */
body.title-up #hud,
body.title-up #hint,
body.title-up #audio-panel,
body.title-up #island-pin { display: none !important; }
body.leaderboard-route #hud,
body.leaderboard-route #hint,
body.leaderboard-route #audio-panel,
body.leaderboard-route #island-pin { display: none !important; }
body.title-up #title-screen.is-story ~ #island-pin:not(.hidden) {
  display: block !important;
}

.ts-logo {
  font-size: clamp(40px, 7vw, 66px);
  letter-spacing: 0.42em;
  margin-right: -0.42em; /* optical centering: tracking pads the right edge */
  font-weight: 600;
  text-shadow: 0 2px 14px rgba(2, 4, 10, 0.95),
    0 0 28px rgba(111, 227, 255, 0.65), 0 0 80px rgba(111, 227, 255, 0.25);
}

.ts-tag {
  margin-top: 16px;
  font-size: 18px;
  letter-spacing: 0.22em;
  margin-right: -0.22em;
  opacity: 0.88;
  text-shadow: 0 1px 8px rgba(2, 4, 10, 0.95);
}

.ts-menu {
  margin-top: 52px;
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 10px;
}

.ts-item {
  position: relative;
  padding: 9px 30px;
  background: none;
  border: none;
  font-family: inherit;
  font-size: 24px;
  font-weight: 600;
  letter-spacing: 0.22em;
  color: var(--ink);
  opacity: 0.85;
  cursor: pointer;
  text-shadow: 0 1px 8px rgba(2, 4, 10, 0.95);
  transition: opacity 0.15s ease, color 0.15s ease;
}
.ts-item.is-selected {
  color: var(--accent);
  opacity: 1;
  text-shadow: 0 1px 8px rgba(2, 4, 10, 0.95), 0 0 16px rgba(111, 227, 255, 0.55);
  outline: none;
}
.ts-item.is-selected::before {
  content: "▸";
  position: absolute;
  left: 6px;
  top: 50%;
  transform: translateY(-50%);
}
.ts-item:focus-visible { outline: none; }

/* Options panels (controls list, sound) */
.ts-panel {
  margin-top: 42px;
  width: min(440px, 92vw);
  max-height: 60vh;
  overflow-y: auto;
  padding: 22px 26px 16px;
  background: var(--panel-bg);
  border: 1px solid rgba(111, 227, 255, 0.28);
  border-radius: 14px;
  box-shadow: 0 26px 80px rgba(2, 4, 10, 0.6), 0 0 40px rgba(111, 227, 255, 0.1);
  backdrop-filter: blur(7px);
}
.ts-group + .ts-group { margin-top: 16px; }
.ts-group-head {
  font-size: 10px;
  letter-spacing: 0.24em;
  font-weight: 700;
  color: var(--accent-warm);
  margin-bottom: 10px;
}
.ts-ctrl {
  display: flex;
  align-items: center;
  gap: 8px;
  padding: 3px 0;
  font-size: 12.5px;
