import { act } from "react"
import { createRoot, type Root } from "react-dom/client"
import { afterEach, beforeEach, describe, expect, it, vi } from "vitest"

import { SessionHeroWindow } from "./SessionHeroWindow"

describe("SessionHeroWindow", () => {
  let container: HTMLDivElement
  let root: Root
  const reactActEnvironment = globalThis as typeof globalThis & {
    IS_REACT_ACT_ENVIRONMENT?: boolean
  }

  beforeEach(() => {
    reactActEnvironment.IS_REACT_ACT_ENVIRONMENT = true
    // jsdom has no ResizeObserver; the scaling effect needs one to run.
    vi.stubGlobal(
      "ResizeObserver",
      class {
        observe() {}
        unobserve() {}
        disconnect() {}
      },
    )
    container = document.createElement("div")
    document.body.appendChild(container)
    root = createRoot(container)
    act(() => {
      root.render(<SessionHeroWindow />)
    })
  })

  afterEach(() => {
    act(() => root.unmount())
    container.remove()
    reactActEnvironment.IS_REACT_ACT_ENVIRONMENT = false
    vi.unstubAllGlobals()
  })

  it("renders both day groups with every session prompt", () => {
    const text = container.textContent ?? ""
    expect(text).toContain("Wednesday 10 Jun")
    expect(text).toContain("Tuesday 9 Jun")
    for (const prompt of [
      "rotate the auth refresh tokens",
      "can you review the auth middleware before I merge?",
      "add rate limiting to the API",
      "fix the flaky tests in the server",
      "migrate the users table to the new schema",
      "add analytics to the onboarding flow",
    ]) {
      expect(text).toContain(prompt)
    }
  })

  it("labels the session list window as Sessions", () => {
    const text = container.textContent ?? ""
    expect(text).toContain("Sessions")
    expect(text).not.toContain("/Sessions")
    expect(text).not.toContain("/Overview")
  })

  it("shows day counts that match the rendered session rows", () => {
    const groupText = (date: string) => {
      const dateLabel = Array.from(container.querySelectorAll("span")).find(
        (el) => el.textContent === date,
      )
      return dateLabel?.closest("div")?.parentElement?.textContent ?? ""
    }

    expect(groupText("Wednesday 10 Jun")).toContain("· 4 sessions")
    expect(groupText("Tuesday 9 Jun")).toContain("· 2 sessions")
  })

  it("shows each row's agent badge, model, and checkpoint count", () => {
    const text = container.textContent ?? ""
    // Agent badge labels resolved from the registry.
    expect(text).toContain("Claude Code")
    expect(text).toContain("Codex")
    expect(text).toContain("Gemini")
    // Models and checkpoint counts.
    expect(text).toContain("Opus 4.8[1m]")
    expect(text).toContain("GPT-5.4")
    expect(text).toContain("8 checkpoints")
    expect(text).toContain("2 checkpoints")
  })
})
