import { useEffect, useState } from "react"

type RotatingWordProps = {
  words: readonly string[]
  /** Fixed text rendered immediately after the rotating word (e.g. ","). */
  suffix?: string
  intervalMs?: number
  className?: string
}

/** Quick exit so the old word clears fast; the swap is timed to this. */
export const FADE_OUT_MS = 120
/** Slightly longer entrance so the new word eases in rather than popping. */
export const FADE_IN_MS = 220

/**
 * Tracks the user's `prefers-reduced-motion` setting.
 *
 * Guards against a missing `matchMedia` so it stays safe under SSR (no `window`)
 * and in test environments (jsdom doesn't implement it) — both default to "no
 * preference", i.e. motion allowed.
 */
function usePrefersReducedMotion(): boolean {
  const [reduced, setReduced] = useState(false)

  useEffect(() => {
    if (typeof window === "undefined" || typeof window.matchMedia !== "function") return

    const query = window.matchMedia("(prefers-reduced-motion: reduce)")
    setReduced(query.matches)

    const onChange = (event: MediaQueryListEvent) => setReduced(event.matches)
    query.addEventListener("change", onChange)
    return () => query.removeEventListener("change", onChange)
  }, [])

  return reduced
}

/**
 * Cycles through `words` with a cross-fade + vertical slide.
 *
 * The slot is sized to the widest word (rendered invisibly) so the surrounding
 * headline never re-flows or "jumps" when a shorter/longer word rotates in.
 *
 * Respects `prefers-reduced-motion`: when the user opts out, the first word is
 * held static with no animation.
 */
export function RotatingWord({
  words,
  suffix = "",
  intervalMs = 1250,
  className = "",
}: RotatingWordProps) {
  const [index, setIndex] = useState(0)
  const [visible, setVisible] = useState(true)
  const prefersReducedMotion = usePrefersReducedMotion()

  // Restart from the first word when the word list changes, so a shorter new
  // array can't leave `index` pointing past its end.
  useEffect(() => {
    setIndex(0)
  }, [words])

  useEffect(() => {
    if (prefersReducedMotion || words.length <= 1) {
      // Hold the current word fully visible when motion is disabled or there's
      // nothing to rotate through.
      setVisible(true)
      return
    }

    let swapTimeout: ReturnType<typeof setTimeout>

    const rotate = setInterval(() => {
      // Clear any still-pending swap before scheduling a new one so timeouts
      // can't stack if intervalMs is ever set shorter than FADE_OUT_MS.
      clearTimeout(swapTimeout)
      setVisible(false)
      // Swap the word once it's faded out, then snap the next one back in.
      swapTimeout = setTimeout(() => {
        setIndex((current) => (current + 1) % words.length)
        setVisible(true)
      }, FADE_OUT_MS)
    }, intervalMs)

    return () => {
      clearInterval(rotate)
      clearTimeout(swapTimeout)
    }
    // Depend on `words` (not `words.length`) so a same-length content change
    // restarts the rotation against the new array.
  }, [words, intervalMs, prefersReducedMotion])

  // Nothing to render with no words. Placed after the hooks (not at the top) so
  // hook order stays stable per the Rules of Hooks.
  if (words.length === 0) return null

  return (
    <span className={`relative inline-grid justify-items-start align-baseline ${className}`}>
      {/*
        Stack every word invisibly in the same grid cell so the slot reserves
        the widest *rendered* width — char count isn't reliable since "decision"
        is visually wider than "tool call" despite being shorter.
      */}
      {words.map((word) => (
        <span
          key={word}
          aria-hidden
          className="invisible col-start-1 row-start-1 whitespace-nowrap"
        >
          {word}
          {suffix}
        </span>
      ))}
      <span
        style={{
          transitionDuration: prefersReducedMotion
            ? "0ms"
            : `${visible ? FADE_IN_MS : FADE_OUT_MS}ms`,
        }}
        className={[
          "col-start-1 row-start-1 whitespace-nowrap text-left transition-all ease-[cubic-bezier(0.22,1,0.36,1)]",
          visible ? "translate-y-0 opacity-100" : "-translate-y-1 opacity-0",
        ].join(" ")}
      >
        {words[index]}
        {suffix}
      </span>
    </span>
  )
}
