// Keep a little depth without compressing the text-heavy session rows.
const ROTATE_X = 24

// useLayoutEffect on the client (measure before paint, no flash); useEffect on the
// server to avoid the SSR warning during prerender.
const useIsomorphicLayoutEffect = typeof window !== "undefined" ? useLayoutEffect : useEffect

/**
 * The session window authored at `designWidth` and scaled to fit its container,
 * so the whole composition shrinks as one unit (like the old contributions
 * canvas) instead of reflowing into oversized text. Laid back in 3D and faded
 * into the page. A narrower `designWidth` scales down less; a wider one reads
 * sleeker on small screens — that's how the mobile and desktop sizes differ.
 */
function ScaledWindow({
  designWidth,
  className,
  compact,
}: {
  designWidth: number
  className?: string
  compact?: boolean
}) {
  const containerRef = useRef<HTMLDivElement>(null)
  const sizerRef = useRef<HTMLDivElement>(null)
  const [scale, setScale] = useState(1)
  const [height, setHeight] = useState<number | undefined>(undefined)

  useIsomorphicLayoutEffect(() => {
    const container = containerRef.current
    const sizer = sizerRef.current
    if (!container || !sizer) return
    const update = () => {
      const next = Math.min(1, container.clientWidth / designWidth)
      setScale(next)
      // offsetHeight ignores the transform, so this is the unscaled layout height.
      setHeight(sizer.offsetHeight * next)
    }
    update()
    const observer = new ResizeObserver(update)
    observer.observe(container)
    return () => observer.disconnect()
  }, [designWidth])

  return (
    <div
      ref={containerRef}
      className={className}
      style={{ position: "relative", width: "100%", height, overflow: "visible" }}
    >
      <div
        ref={sizerRef}
        style={{
          position: "absolute",
          top: 0,
          left: 0,
          width: designWidth,
          transform: `scale(${scale})`,
          transformOrigin: "top left",
          perspective: "min(1500px, 100vw)",
          perspectiveOrigin: "50% 40%",
        }}
      >
        {/* Tilt on the outer div; clip on the inner. overflow:hidden does NOT
            clip descendants when it shares an element with a 3D transform, so
            the two must be separate or the rows spill past the edge. */}
        <div style={{ transform: `rotateX(${ROTATE_X}deg)`, transformOrigin: "50% 0" }}>
          <div
            style={{
              width: designWidth,
              borderRadius: 14,
              overflow: "hidden",
              border: "1px solid var(--border-default)",
              background: "var(--surface-raised)",
              boxShadow: "0 1px 2px rgba(0,0,0,0.04), 0 30px 60px rgba(0,0,0,0.10)",
              maskImage:
                "linear-gradient(to bottom, black 48%, rgba(0,0,0,0.4) 72%, transparent 100%)",
              WebkitMaskImage:
                "linear-gradient(to bottom, black 48%, rgba(0,0,0,0.4) 72%, transparent 100%)",
            }}
          >
            <SessionList compact={compact} />
          </div>
        </div>
      </div>
    </div>
  )
}

