const outputDelays = [300, 400, 300, 400, 400, 300, 400, 200, 300]

export function AnimatedTerminal() {
  const [phase, setPhase] = useState<AnimationPhase>("waiting")
  const [typedChars, setTypedChars] = useState(0)
  const [visibleOutputs, setVisibleOutputs] = useState(0)
  const [showTypingCursor, setShowTypingCursor] = useState(true)
  const [selectedAgents, setSelectedAgents] = useState<Set<number>>(new Set())
  const [cursorIndex, setCursorIndex] = useState(0)
  const selectedNamesRef = useRef<string[]>([])
  const containerRef = useRef<HTMLDivElement>(null)
  const hasAnimatedRef = useRef(false)

  // Start animation when component comes into view
  useEffect(() => {
    const observer = new IntersectionObserver(
      (entries) => {
        entries.forEach((entry) => {
          if (entry.isIntersecting && !hasAnimatedRef.current) {
            hasAnimatedRef.current = true
            setPhase("idle")
          }
        })
      },
      { threshold: 0.5 },
    )

    if (containerRef.current) {
      observer.observe(containerRef.current)
    }

    return () => observer.disconnect()
  }, [])

