  useEffect(() => {
    if (phase !== "idle") return
    const timeout = setTimeout(() => setPhase("typing"), 600)
    return () => clearTimeout(timeout)
  }, [phase])

  // Typing animation
  useEffect(() => {
    if (phase !== "typing") return

    if (typedChars < command.length) {
      const timeout = setTimeout(() => setTypedChars((prev) => prev + 1), 60 + Math.random() * 40)
      return () => clearTimeout(timeout)
    } else {
      const timeout = setTimeout(() => setPhase("selection"), 400)
      return () => clearTimeout(timeout)
    }
  }, [phase, typedChars])

  // Selection phase — start empty, randomly pick 2 of 5 agents
  useEffect(() => {
    if (phase !== "selection") return

    // Pick 2 random agents
    const indices = [0, 1, 2, 3, 4]
    for (let i = indices.length - 1; i > 0; i--) {
      const j = Math.floor(Math.random() * (i + 1))
      ;[indices[i], indices[j]] = [indices[j]!, indices[i]!]
    }
    const pick: [number, number] = [indices[0]!, indices[1]!]

    const sorted = [...pick].sort((a, b) => a - b)
    selectedNamesRef.current = sorted.map((i) => agentNames[i]!)

    setSelectedAgents(new Set())
    setCursorIndex(pick[0])

    const timeouts: number[] = []
    let t = 0

    // Select first agent
    t += 700
    timeouts.push(
      window.setTimeout(() => {
        setSelectedAgents(new Set([pick[0]]))
      }, t),
    )

    // Move cursor step by step to second agent
    const direction = pick[1] > pick[0] ? 1 : -1
    const steps = Math.abs(pick[1] - pick[0])
    for (let s = 1; s <= steps; s++) {
