    !isIconButton && !isOutlineButton && condensed && "px-2",
    variantStyles[variant],
    className,
  )

  // Check if children contains mixed content (icon + text)
  const childArray = Children.toArray(children)
  const hasMultipleChildren = childArray.length > 1
  const hasIconChild = childArray.some((child) => isValidElement(child) && child.type !== "string")
  const isSingleTextChild =
    childArray.length <= 1 &&
