  const content = isIconButton ? (
    children
  ) : hasMultipleChildren && hasIconChild ? (
    // Button with icon + text: wrap only text nodes in truncate span, prevent icon from shrinking
    <>
      {childArray.map((child, index) =>
        isValidElement(child) ? (
          <span key={index} className="flex shrink-0">
            {child}
          </span>
        ) : (
          <span key={index} className="min-w-0 truncate">
            {child}
          </span>
        ),
      )}
    </>
  ) : isSingleTextChild ? (
    // Text-only button: wrap everything in truncate span
    <span className="min-w-0 truncate">{children}</span>
  ) : (
    // Single non-text child (e.g. a component rendering icon + label): keep its
    // content inline so block-level SVGs don't wrap onto their own line.
    <span className="flex min-w-0 items-center justify-center gap-1.5">{children}</span>
  )

  const renderedContent = isOutlineButton ? (
    <span
      data-button-shell
