    const text = tooltipText ?? label
    if (!text) return element

    return (
      <Tooltip
        text={text}
        relationship={tooltipRelationship ?? (tooltipText === undefined ? "label" : "description")}
        position={tooltipPosition}
        closeOnClick={tooltipCloseOnClick}
      >
        {element}
