    const linkProps = rest as ButtonAsLink
    const link = (
      <a
        ref={ref as React.Ref<HTMLAnchorElement>}
        href={linkProps.href}
        target={linkProps.target}
        rel={linkProps.rel}
        className={classes}
        aria-disabled={disabled}
        onClick={disabled ? undefined : linkProps.onClick}
        {...(linkProps as AnchorHTMLAttributes<HTMLAnchorElement>)}
