    if (isIconButton) {
      return renderIconButtonTooltip(link, linkProps["aria-label"])
    }

    return link
  }

  // Button
  const buttonProps = rest as ButtonAsButton
  const button = (
    <button
      ref={ref as React.Ref<HTMLButtonElement>}
      type={buttonProps.type || "button"}
      onClick={buttonProps.onClick}
      disabled={disabled}
      className={classes}
      {...(buttonProps as ButtonHTMLAttributes<HTMLButtonElement>)}
    >
      {renderedContent}
    </button>
  )

  // Wrap icon buttons with tooltip if they have aria-label
  if (isIconButton) {
    return renderIconButtonTooltip(button, buttonProps["aria-label"])
  }

  return button
