        const depth = h / seaLevel; // 0 deep .. 1 coast
        const col = mix(DEEP, SHALLOW, Math.pow(depth, 1.2) * (0.85 + tide * 0.3));
        r = col[0]; g = col[1]; b = col[2];
        elev = 0.45;
